parameters.jsCode:
const raw = $input.first().json;
const body = raw.body || raw;
return [{ json: {
  lead_id: body.lead_id || body.id || null,
  name: body.name || 'Unknown',
  phone: body.phone || null,
  email: body.email || null,
  channel: body.channel || 'unknown',
  reason: body.reason || 'Unspecified escalation',
  last_message: body.last_message || body.message || '',
  escalated_at: new Date().toISOString()
}}];

const escalation = $node['Parse Escalation Data'].json;
const leadRaw = $node['Fetch Lead Profile'].json;
const historyRaw = $node['Fetch Interaction History'].json;

const lead = Array.isArray(leadRaw) ? leadRaw[0] : leadRaw;
const history = Array.isArray(historyRaw) ? historyRaw : [];

const historyText = history.map(h => 
  `[${h.direction}] ${h.channel}: ${h.message_text?.substring(0, 100)}`
).join('\n') || 'No prior interactions logged';

return [{ json: {
  ...escalation,
  leadProfile: lead || {},
  interactionHistory: historyText,
  hasLeadProfile: !!lead?.id
}}];

