parameters.jsCode:
const aiResponse = $input.first().json;
const context = $node['Build Escalation Context'].json;

let summary;
try {
  summary = aiResponse.choices[0].message.content.trim();
} catch (e) {
  summary = `Lead ${context.name} escalated from ${context.channel}. Reason: ${context.reason}. Manual review needed.`;
}

return [{ json: { ...context, ai_summary: summary } }];

